class Solution {
public:
    int numberOfWays(int n, int x) {
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j * j * ... * j <= i; j++) {
                int p = pow(j, x);
                if (p <= i) {
                    dp[i] = (dp[i] + dp[i - p]) % MOD;
                }
            }
        }
        return dp[n];
    }
};

